var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"솔직히 놀랐습니다. 설마 여기까지 올 거라고는 생각 못했거든요.","JPN":"正直、驚きました。まさかここまで辿り着くとは思っていませんでしたから。","ENG":"I was honestly surprised. I didn't think you'd make it here.","TWN":"說實話，我很驚訝。沒想到你們真的會走到這一步。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"부사장님…? 여긴 대체 어떻게 오신 거예요?","JPN":"副社長……？　ここにはどうやって？","ENG":"Vice President...? How did you come all the way here?","TWN":"副總……？你怎麼來了？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…아니. 이 사람 저 사람 본 시점에서 아무 의미 없는 질문이려나.","JPN":"……いや、色んな人たちに会っているわけだし、野暮な質問でしたね。","ENG":"...Well. I guess it's not really worth asking considering all the others we've encountered so far.","TWN":"……不，從之前遇到的那些人看來，這個問題根本沒意義吧？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"뭘 좀 아시는군요. 저희가 재회의 기쁨을 만끽할 만큼 각별한 사이는 아니죠.","JPN":"よくおわかりで。私たちは再会の喜びを分かち合うほど、親しい仲でもありませんよね。","ENG":"Glad we can skip that part. We're not really close enough to rejoice in reuniting.","TWN":"悠菲很聰明呢。我們的關係沒有熟到能享受重逢的喜悅吧。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"뭐래. 그냥 넘어간다는 소리도 아니거든요?","JPN":"だからといって、なかったことにしてもいいとは言ってませんからね。","ENG":"That doesn't mean we can skip all the questions.","TWN":"說什麼呢。我可沒想就這麼算了？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"타이탄 씨나 알트 소대도 그렇고. 대체 다른 분들에게 무슨 말을 하신 거예요?","JPN":"タイタンさんやアルト小隊、そして他の方々に、いったい何を吹き込んだんですか？","ENG":"Titan, and ALT Squad. What on earth did you tell them?","TWN":"泰坦先生和阿爾特小隊也是，你到底對他們說了什麼？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"무슨 말씀인지 도통 모르겠군요. 제가 처음부터 말씀드리지 않았습니까?","JPN":"何のことでしょう。初めから言いましたよね？","ENG":"I don't know what you're talking about.","TWN":"我完全不明白你在說什麼。我不是從一開始就已經說明了嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"유피 양이 해결해야 할 <color=#ffd34c>과제</color>가 있다고.","JPN":"ユピさんが解決すべき<color=#ffd34c>課題</color>があると。","ENG":"However, I did tell you in the beginning, that there is a <color=#ffd34c>task</color> you have to complete.","TWN":"悠菲有一個<color=#ffd34c>任務</color>要完成。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그러니까, 지금까지 전부 코핀 컴퍼니의 입사 시험이었다?","JPN":"つまり、これは全部コフィンカンパニーへの入社試験だったってことですか？","ENG":"You're meaning to say that this was all part of the test to get into Coffin Company?","TWN":"所以說，到目前為止這一切都是科芬公司的入職測試嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"경영진으로서 회사에 범죄자를 받아들이는 게 어디 쉬운 일이겠습니까.","JPN":"副社長として会社に犯罪者を受け入れることは簡単なことではありません。","ENG":"As an executive, I can't accept an individual with a criminal record without a good reason.","TWN":"作為管理層，接納罪犯進入公司可不是件容易的事。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"레이첼 양의 추천이 있다고 한들, 유피 양이 어떤 사람인지 알아볼 필요가 있었죠.","JPN":"あのレイチェルさんからの推薦だったとはいえ、ユピさんがどんな方なのかを調べる必要がありました。","ENG":"Even though Rachel recommended you, I still needed to see what kind of person you were.","TWN":"即便有瑞秋的推薦，也有必要了解一下悠菲是怎樣的人。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"축하드립니다, 유피 양. 시험은 합격이에요.","JPN":"おめでとうございます、ユピさん。あなたは合格しました。","ENG":"Congratulations, Yuppie. You passed the test.","TWN":"恭喜你，悠菲。你通過了測試。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"전부 끝났으니 상자를 돌려주고 떠나시죠. 뒷일은 제가 잘 처리하겠습니다.","JPN":"試験は終了したので、箱をこちらに返し、島を離れてください。後始末は私にお任せを。","ENG":"Since it's all over, you are to return the chest and leave. I'll take care of the rest.","TWN":"既然都結束了，把箱子還給我，然後你就可以離開了。後面的事我會處理好的。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"있죠, 부사장님. 아무리 제가 을이라도 이렇게 막 나가시면 안 되죠.","JPN":"あの、副社長。いくら私の立場が低いとはいえ、こんなやり方はどうかと思います。","ENG":"You know, Vice President. You may be in a higher position than me, but this is too much.","TWN":"副總……雖然我只是個小員工，但你也不能這樣呼來喚去吧。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"이거 하나 얻겠다고 얼마나 고생했는지 아세요?","JPN":"これを手に入れるために、いったいどれだけ苦労したかわかりますか？","ENG":"Do you know how much I went through to get this one thing?","TWN":"為了得到這個箱子，你知道我有多辛苦嗎……？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"맞아, 부사장 아줌마. 게임은 치사하면 안 된다구.","JPN":"そうだよ、副社長のおばさん。ゲームは正々堂々勝負しなきゃ。","ENG":"Yeah, Vice President. You should play fair and square.","TWN":"沒錯，副總大嬸。玩遊戲可不能耍賴喔。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"잘 생각하시죠, 유피 양. 제 앞에서의 모든 행실은 처우협의 과정에 반영됩니다.","JPN":"ユピさん、よく考えて行動してください。あなたの言動はすべて、これからの処遇協議の過程に反映されるんですよ。","ENG":"Think carefully, Yuppie. Whatever you do in my presence will be taken into account for your contract negotiation.","TWN":"好好考慮一下，悠菲。你在我面前的所有行為都會反映在待遇協商的結果裡。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"역시 싫어요.","JPN":"やっぱり嫌です。","ENG":"No.","TWN":"不要。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"제대로 된 설명 하나 없이 이대로 가라고 해도 납득할 수 있을 리가 없잖아요.","JPN":"ちゃんとした説明もなしに、このまま帰れと言われても、納得できるはずがありません。","ENG":"You can't expect me to just accept all that without a proper explanation.","TWN":"不給我一個合理的解釋就讓我走，這樣做我不接受！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"…예상대로군요. 그리 쉽게 포기할 인간이었다면 여기에 오지도 못했겠죠.","JPN":"……やはりそうですか。そう簡単に諦めるような人なら、そもそもここまで来られるはずがありませんものね。","ENG":"...Of course. You wouldn't have made it this far if you were someone who gave up easily.","TWN":"……果然不出所料。如果你是容易放棄的人，也不會來到這裡了吧。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"유감입니다.","JPN":"とても残念です。","ENG":"But that's a shame.","TWN":"真遺憾。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"히이이익?!","JPN":"ひいい！？","ENG":"Eeeek!","TWN":"欸欸欸？!"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"저… 저 사람. 방금 절 베려 했어요. 절 죽이려 했다고요!","JPN":"あの……あの人、私に斬りかかりましたよね。私を殺そうとしましたよね！？","ENG":"S-she... just tried to cut me. She tried to kill me!","TWN":"那……那個人，剛剛想砍我。她想殺了我！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"엄살 떨지 마시죠. 칼등에는 맞아도 안 죽습니다.","JPN":"大袈裟です。峰打ちですから、死にはしません。","ENG":"No need to exaggerate this. You won't die from getting hit by the back of a knife.","TWN":"別裝了。就算被刀背打到也不會死的。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"칼등으로는 친다는 거잖아! 이거 엄연한 사내폭력인 거 몰라요?","JPN":"結局殴るってことでしょう？　こんなの社内暴力です！","ENG":"You were still going to hit me with it! That's workplace violence!","TWN":"用刀背打也是打啊！你不知道這是明顯的職場暴力嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"어떡하죠, 실장님? 방금 움직임을 보니 여간 대단한 분이 아닌 것 같은데요.","JPN":"どうしましょう、室長。今の動き、相当な手練れのようです。","ENG":"What do we do, Chief? She seems extremely skilled in combat.","TWN":"怎麼辦，室長？剛才看動作，感覺副總不是一般的厲害啊……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"음. 확실히 부사장 아줌마는 반칙에도 아랑곳하지 않아.","JPN":"そうだね。副社長のおばさんは反則技をもいとわずに使うような人間だし。","ENG":"Mmm. I do know that cheating doesn't work on the Vice President, either.","TWN":"嗯。確實，副總大嬸從來不在乎犯規。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"하지만 선장님도 이럴 때를 대비해 부사장 아줌마 전용 특별 대비책을 마련해 놨다구?","JPN":"でも船長だってこんなときのために、対副社長のおばさん用に切り札を用意してるんだ。","ENG":"But your captain prepared a solution exclusively for the Vice President!","TWN":"但是西格瑪船長也不是省油的燈，我有特別這種情況準備了對付副總大嬸的對策！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"목걸이에 손을 올려봐, 유피.","JPN":"ネックレスに手を当ててみて、ユピ。","ENG":"Put your hand on your necklace, Yuppie.","TWN":"把手放在項鍊上，悠菲。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"네? 손을요?","JPN":"はい？　手ですか？","ENG":"Huh? My hand?","TWN":"什麼？手嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"테라브레인 서브 모듈 인식.","JPN":"テラブレイン、サブモジュールを認識。","ENG":"Recognizing Terrabrain submodule...","TWN":"特拉大腦輔助模組識別。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_76"},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"동기화 성공. 에너지 충전 완료.","JPN":"同期に成功。エネルギーチャージ完了。","ENG":"Synchronized. Energy charging completed.","TWN":"同步成功，充能完畢。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_76"},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"호출 코드 입력을 기다리고 있습니다.","JPN":"呼び出しコードを入力してください。","ENG":"Waiting for you to enter summon code.","TWN":"等待輸入呼叫代碼。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_76"},{"id":"L47_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"흐읍……!","JPN":"ふうっ……！","ENG":"*Takes a deep breath*","TWN":"唔……！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"아빠! 도와줘!!","JPN":"パパ！　助けて！！","ENG":"Daddy! Help!","TWN":"爸爸！幫幫我！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GAP_SILVER_NULL_NULL","text":{"KOREA":"내가 왔다!","JPN":"来たぞ！","ENG":"Here I come!","TWN":"我來了！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_SILVER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GAP_SILVER_NULL_NULL","text":{"KOREA":"감히 누가 우리 딸, 기를 죽이고 그러지? 네놈인가?!","JPN":"誰がうちの愛娘をいじめたんだ？　貴様か！？","ENG":"Who's bullying my lovely daughter? Is that you?","TWN":"誰敢欺負我的女兒？是你嗎？！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_SILVER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"부사장 아줌마가 그랬어! 아빠, 혼내 줘!","JPN":"副社長のおばさんだよ、パパ！　やり返して！","ENG":"It was the Vice President! Take her down, Daddy!","TWN":"是副總大嬸！爸爸，快幫我教訓她！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAP_SILVER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GAP_SILVER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAP_SILVER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"아빠! 어디가!!","JPN":"パパ！　どこ行くの！？","ENG":"Daddy! Where are you going?!","TWN":"爸爸！你要去哪！！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"오자마자 배신이라니. 당신이 무슨 크레데레예요!?","JPN":"助けに来たとたん裏切るなんて、あなたはクレデレですか！？","ENG":"You're betraying us right away? Are you pulling a \\"Credere\\"?!","TWN":"喔喔，剛來就落跑，你也是克蕾妲莉嗎！？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"GAP_SILVER_NULL_NULL","text":{"KOREA":"미, 미안하네. 원래 혈연에만 집중하면 회사가 기운다는 소리가 있지 않나.","JPN":"す、すまないな。血縁ばかりにこだわったら会社が回らなくなるんだ。","ENG":"I-I'm sorry. I can't take sides in matters involving the family and the company.","TWN":"對、對不起。不是有句話說，只顧血緣的話公司會垮的嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_SILVER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GAP_SILVER_NULL_NULL","text":{"KOREA":"부사장이 화나면 회사가 돌아가질 않아요.","JPN":"副社長の機嫌を損ねれば、会社運営が破綻してしまう。","ENG":"The company doesn't function properly if the Vice President gets angry.","TWN":"這個……副總一發火，公司就運轉不起來了。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_SILVER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GAP_SILVER_NULL_NULL","text":{"KOREA":"우리 딸. 미안하지만 한 번만 참아주지 않으련?","JPN":"娘よ。すまないが、今回ばかりは目をつむってくれるかい？","ENG":"My sweet daughter. I'm sorry, but can you let this slide this once?","TWN":"抱歉，我的女兒……這次能不能先忍忍？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_SILVER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"말 한 번 잘하셨습니다, 사장님. 애들 장난이라도 계속 받아줄 수는 없는 법이죠.","JPN":"よく言ってくれました、社長。子どもたちを甘やかし続けるのもよくありませんからね。","ENG":"I'm glad you said that, Boss. You can't keep putting up with children's play.","TWN":"說得好，老闆。再怎麼樣也不能一直縱容小孩子的惡作劇吧？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GAP_SILVER_NULL_NULL","text":{"KOREA":"그나저나 부사장. 대체 무슨 일이 있었길래 둘이 싸우는 건가…?","JPN":"ところで、副社長。二人が喧嘩しているのはいったいどうしてなのかね……？","ENG":"Anyway, Vice President, why are you two fighting in the first place...?","TWN":"話說回來，副總。到底發生了什麼事，你們倆才會打起來……？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_SILVER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"별거 아닙니다. 조용히 묻힌 구관리국 시절의 비밀이 만천하에 드러나게 생겨서 말이죠.","JPN":"大したことではありません。忘れ去られた旧管理局時代の機密事項が、世界中に公表されようとしていますので。","ENG":"It's nothing serious. A secret from the Old Administration era was almost dug up to be revealed to the whole world.","TWN":"沒什麼特別的，只不過是舊管理局時期的秘密即將被公之於眾了。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"처분하랬더니 관리 로봇까지 붙여서 보관하시다니.","JPN":"処分をお願いしたはずですが、管理ロボットまでつけてご丁寧に保管していたとは。","ENG":"I told you to get rid of it. I can't believe you kept it with its own robot to take care of it.","TWN":"讓你處理掉，結果你還派了管理機器人來保管。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"역시 최고 관리자께서는 배포가 남다르십니다.","JPN":"さすが、最高管理者は普通の人とは違いますね。","ENG":"How generous of you, Supreme Administrator.","TWN":"不愧是最高管理者，真是大手筆。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GAP_SILVER_NULL_NULL","text":{"KOREA":"그, 그게. 내 나름대로의 성의라고나 할까.","JPN":"そ、それは。私なりのけじめのつけ方だったというか……","ENG":"W-well. I was just trying to be thoughtful.","TWN":"那、那個。這算是我的一點心意吧。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_SILVER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GAP_SILVER_NULL_NULL","text":{"KOREA":"그래도 나름 추억이 서려 있는 물건이니 나중에 보면 또 다르겠지, 싶어서…….","JPN":"一応、思い出が詰まっているんだからな。あとで見返したら感想が変わるかもしれないじゃないか……","ENG":"I thought, maybe you'd feel differently later on, since it holds memories...","TWN":"畢竟是充滿回憶的物品，以後再看可能會有不同的感受……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_SILVER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"가져오시죠.","JPN":"こちらに持ってきてください。","ENG":"Bring it here.","TWN":"拿來吧。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GAP_SILVER_NULL_NULL","text":{"KOREA":"넵.","JPN":"はい。","ENG":"Yes, ma'am.","TWN":"是。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_SILVER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};